sp_widget.client_script:
api.controller=function($scope, $window, $location) {
    var c = this;

    c.$onInit = function() {

        var params = $location.search();

        if (params.name && params.cn && params.set) {
            console.log('Loading card via URL params');

            // Call server / script include here using params
            c.data = {
                name: params.name,
                cn: params.cn,
                set: params.set
            };

            return;
        }

        // Fallback to sessionStorage (optional)
        var stored = $window.sessionStorage.getItem('mtg_selected_card');

        console.log('Fallback sessionStorage:', stored);

        if (stored) {
            c.card = JSON.parse(stored);
        } else {
            console.warn('No card data available');
        }
    };
}

sp_widget.css:
.mtg-card-detail {
  max-width: 1200px;
  margin: 0 auto;
}

.mtg-card-detail__main {
  display: grid;
  grid-template-columns: 300px 1fr;
  gap: var(--mtg-spacing-lg);
}

/* Reuse existing card image behavior */
.mtg-card__image-wrapper {
  position: relative;
}

.mtg-card__image {
  width: 100%;
  border-radius: var(--mtg-radius-md);
}

/* Keep foil overlay consistent */
.mtg-card__foil {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  pointer-events: none;
}

/* Info section spacing */
.mtg-card__info {
  display: flex;
  flex-direction: column;
  gap: var(--mtg-spacing-sm);
}

/* Sections */
.mtg-card-detail__section {
  margin-top: var(--mtg-spacing-xl);
}

/* Rulings */
.mtg-card-detail__rulings {
  display: flex;
  flex-direction: column;
  gap: var(--mtg-spacing-sm);
}

.mtg-card-detail__ruling {
  padding: var(--mtg-spacing-sm);
  border-radius: var(--mtg-radius-sm);
  background: var(--mtg-surface);
}

.mtg-card-detail__ruling img{
 width: var(--fs-lg);
}

/* Printings grid aligns with your existing grid system */
.mtg-printings-grid {
  margin-top: var(--mtg-spacing-md);
}

.mtg-card__oracle img{
 width: var(--fs-lg);
}

sp_widget.script:
(function() {

    data.result = {
        success: true,
        message: '',
        method: 'cardDetailInit',
        record: {}
    };

    try {

        data.params = {
            name: $sp.getParameter('name'),
            cn: $sp.getParameter('cn'),
            set: $sp.getParameter('set'),
            foil: $sp.getParameter('foil'),
            debug: $sp.getParameter('db')
        };

        // Only call server if we have params
        if (data.params.name && data.params.cn && data.params.set) {

            var cardAPI = new x_759224_magic_c_0.CardAPI();

            var res = cardAPI.getCardByNaturalKey({
                name: data.params.name,
                collector_number: data.params.cn,
                set_code: data.params.set,
                foil: data.params.foil
            });

            data.result = res;

        } else {
            data.result.success = false;
            data.result.message = 'Missing required parameters';
        }

        data.showDebug = gs.hasRole('admin') && data.params.db === 'true';

    } catch (ex) {
        data.result.success = false;
        data.result.message = ex.message;
    }

})();
